CREATE TABLE appuser.Stations (
	station_id NUMBER(19) PRIMARY KEY,
	id NUMBER(19) UNIQUE,
	name VARCHAR2(255) NOT NULL,
	longitude NUMBER(9,6) NOT NULL,
	latitude NUMBER(9,6) NOT NULL,
	address VARCHAR2(255),
	city VARCHAR2(120),
	state VARCHAR2(120),
	postal_code VARCHAR2(20),
	capacity NUMBER(10),
	capacity_available NUMBER(10),
	bikes_available NUMBER(10),
	created_at TIMESTAMP,
	updated_at TIMESTAMP
);

CREATE TABLE appuser.Users (
	id NUMBER(19) PRIMARY KEY,
	user_id NUMBER(19) UNIQUE,
	first_name VARCHAR2(120),
	last_name VARCHAR2(120),
	email VARCHAR2(255),
	phone VARCHAR2(40),
	credit_card_num VARCHAR2(32),
	is_member NUMBER(1),
	created_at TIMESTAMP,
	updated_at TIMESTAMP
);

CREATE TABLE appuser.Bikes (
	id NUMBER(19) PRIMARY KEY,
	bike_id NUMBER(19) UNIQUE,
	brand VARCHAR2(120),
	model VARCHAR2(120),
	bike_type VARCHAR2(80),
	status VARCHAR2(40),
	station_id NUMBER(19) NOT NULL,
	purchased_at DATE,
	created_at TIMESTAMP,
	updated_at TIMESTAMP,
	CONSTRAINT fk_bikes_station FOREIGN KEY (station_id) REFERENCES appuser.Stations(station_id)
);

