UPDATE APPUSER.STATIONS SET CAPACITY_AVAILABLE = CAPACITY - (SELECT COUNT(1) FROM BIKES WHERE BIKES.STATION_ID = STATIONS.station_id and STATUS = 'available');

UPDATE STATIONS SET BIKES_AVAILABLE = (SELECT COUNT(1) FROM BIKES WHERE BIKES.STATION_ID = STATIONS.station_id and STATUS = 'available');

